const express = require('express');
const multer = require('multer');
const path = require('path');
const fs = require('fs');

const uploadDir = 'public/uploads';
const thumbnailDir = 'public/thumbnails';

const storage = multer.diskStorage({
  destination: function (req, file, cb) {
    if (!fs.existsSync(uploadDir)) {
      fs.mkdirSync(uploadDir);
    }
    cb(null, uploadDir);
  },
  filename: function (req, file, cb) {
    const ext = path.extname(file.originalname).toLowerCase();
    let filename;
    switch (ext) {
      case '.jpg':
      case '.jpeg':
        filename = `${file.fieldname}-${Date.now()}.jpg`;
        break;
      case '.png':
        filename = `${file.fieldname}-${Date.now()}.png`;
        break;
      case '.gif':
        filename = `${file.fieldname}-${Date.now()}.gif`;
        break;
      case '.svg':
        filename = `${file.fieldname}-${Date.now()}.svg`;
        break;
      case '.pdf':
        filename = `${file.fieldname}-${Date.now()}.pdf`;
        break;
      case '.doc':
        filename = `${file.fieldname}-${Date.now()}.doc`;
        break;
      case '.docx':
        filename = `${file.fieldname}-${Date.now()}.docx`;
        break;
      case '.zip':
        filename = `${file.fieldname}-${Date.now()}.zip`;
        break;
      default:
        filename = `${file.fieldname}-${Date.now()}${ext}`;
    }
    cb(null, filename);
  },
});

const upload = multer({
  storage: storage,
  fileFilter(req, file, cb) {
    const ext = path.extname(file.originalname).toLowerCase();
    if (['.jpg', '.jpeg', '.png', '.gif', '.svg', '.pdf', '.doc', '.docx', '.zip'].includes(ext)) {
      cb(null, true);
    } else {
      cb(new Error('Only image and document files are allowed!'));
    }
  },
});

const router = express.Router();

router.post('/upload-avatar', upload.single('avatar'), (req, res) => {
  const filename = req.file.filename;
  const ext = path.extname(filename).toLowerCase();
  if (['.jpg', '.jpeg', '.png', '.gif'].includes(ext)) {
    generateThumbnail(filename);
  }
  res.json({ message: `File uploaded successfully!`, filename });
});

router.post('/upload-document', upload.single('document'), (req, res) => {
  const filename = req.file.filename;
  res.json({ message: `File uploaded successfully!`, filename });
});

function generateThumbnail(filename) {
  const img = new Jimp(path.join(uploadDir, filename), function(err, image) {
    if (err) return console.error(err);
    image.resize(100, 100).write(path.join(thumbnailDir, filename));
  });
}

module.exports = router;